"""
MKT Original Language Commentary — Psalms chapters 147–150
Run: python3 scripts/zc-original-psalms-147-150.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/psalms.json

Key decisions in this range:
- Ps 147: bipartite hymn (vv 1–11 general praise; vv 12–20 Zion-specific); LXX splits it
  into two psalms (LXX Ps 146 + 147); post-exilic provenance likely (rebuilt Jerusalem, v2)
- Ps 147:4: sāpar (count) echoes Gen 15:5 — the God who told Abraham the stars cannot be
  counted now counts every one by name; juxtaposed with the brokenhearted individual in v3
- Ps 147:11: ḥāpēṣ (delight) reversed from v10 — no delight in horse/legs; full delight in
  those who fear YHWH and hope in his ḥesed (covenant loyalty)
- Ps 147:19–20: YHWH's dābār to Israel is the same word that commands weather (vv 15–18) —
  Torah and cosmos share the same divine speech-act
- Ps 148: cosmic praise psalm; v5 uses the creation formula (ṣiwwāh wĕniḇrāʾû); tannînim
  (sea monsters of v7) are called to praise, reversing the chaos-monster mythology
- Ps 148:14: qeren (horn) raised = Messianic/covenantal vindication imagery
- Ps 149: ḥăsîdîm as the subject of both praise (v1) and eschatological judgment (vv 6–9);
  the dual image of praise-in-mouth + sword-in-hand is not contradicted; "judgment written"
  (v9) refers to the covenant curses of Deut 28–32 enacted through historical agents
- Ps 150: Grand Doxology of the Psalter; 13 hallĕlû forms in 6 verses; kōl hanĕšāmāh
  (everything that has breath) = the broadest possible inclusion, closing the entire book
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 147–150 — the closing Hallel sequence and Grand Doxology;
#   49 verses covering the final four psalms of the Psalter.
# CHANGE? If commentary/mkt-original/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json'));
#   [print(ch, len(d[ch])) for ch in [str(i) for i in range(147,151)]]"

PSALMS = {
  "147": {
    "1": '<p><strong>hallĕlû-yāh kî ṭôb zammĕrāh ʾĕlōhênû kî nāʿîm nāweh tĕhillāh</strong> — "Praise the LORD! For it is good to sing praises to our God; for it is pleasant, and praise is fitting." Three motivation-words stack in v1: <em>ṭôb</em> (good, morally and aesthetically excellent), <em>nāʿîm</em> (pleasant, delightful — the root of the name Naomi, Ruth 1:20), and <em>nāweh</em> (comely, beautiful, fitting — used of a bride\'s beauty in Isa 52:7; here applied to the act of praise itself). The word-order in Hebrew places the praise-act first and then unpacks its qualities; the invitation is both aesthetic and theological: praise is fitting because it corresponds to who God is.</p>',
    "2": '<p><strong>bônēh yĕrûšālayim yhwh niddĕḥê yiśrāʾēl yĕkannēs</strong> — "the LORD builds up Jerusalem; he gathers together the outcasts of Israel." The active participle <em>bônēh</em> (building, Qal participle from <em>bānāh</em>) presents the act as ongoing, not completed — YHWH is the perpetual builder of Zion. <em>niddĕḥê</em> (the outcasts/scattered ones, Niphal participle of <em>nādaḥ</em>, to drive away, banish) — the participle carries the social reality of exile: people forcibly pushed to the margins. <em>yĕkannēs</em> (gathers together, Piel imperfect of <em>kānaś</em>) — the Piel intensive marks the thoroughness of the gathering; what was dispersed is completely assembled. Post-exilic Jerusalem reads this as the return from Babylon (Isa 56:8; Ezek 34:13).</p>',
    "3": '<p><strong>hārōpēʾ lišbûrê lēb ûmĕḥabbēš lĕʿaṣṣĕbôtām</strong> — "he heals the brokenhearted and bandages their wounds." Two paired verbs: <em>rāpāʾ</em> (heal, Qal participle — the root of Raphael and rĕpāʾîm; the medical metaphor of divine therapy) and <em>ḥābāš</em> (bind up/bandage wounds, Piel participle — the verb used for binding a wound in Isa 1:6 and for YHWH binding the broken of Isa 61:1). <em>šibūrê lēb</em> (brokenhearted, literally "broken of heart" — <em>šābar</em> in Niphal participle + <em>lēb</em>) — the same construction appears in Isa 61:1, the Servant\'s commission. The juxtaposition of v2 (gathering scattered exiles) with v3 (healing inner wounds) is deliberate: restoration is both political and personal.</p>',
    "4": '<p><strong>môneh mispār lakkôkābîm lĕkullām šēmôt yiqrāʾ</strong> — "he counts the stars by number; he calls them all by name." <em>mānāh</em> (counts, Qal participle — used for census-taking and rationing; the root of <em>mĕnāʾēl</em>, God has numbered) + <em>mispār</em> (number, count) — the combination emphasizes enumeration. The tension with v4b is deliberate: the stars are innumerable (Gen 15:5, where YHWH challenged Abraham to count them), yet YHWH assigns each one a number. <em>lĕkullām šēmôt yiqrāʾ</em> (to all of them he calls names) — naming as an act of sovereignty and intimate knowledge; in ANE thought, to name something was to define its nature and own it (Gen 1:5, 8, 10; 2:19–20). The God who knows the name of every star also knows the wound of every broken heart (v3) — the psalm\'s central theological paradox: cosmic omniscience and pastoral intimacy are the same attribute.</p>',
    "5": '<p><strong>gādôl ʾădōnênû wĕrabbāh kōaḥ lîtĕbûnātô ʾên mispār</strong> — "great is our Lord and abundant in power; his understanding has no number/limit." <em>gādôl</em> (great) + <em>rabbāh kōaḥ</em> (abundant/great power) are familiar divine epithets, but the verse\'s force is in the final phrase: <em>lîtĕbûnātô ʾên mispār</em> — "of his understanding there is no number." <em>tĕbûnāh</em> (understanding, discernment, from <em>bîn</em>) is the faculty of deep insight — the same noun as in Prov 3:19 ("by understanding he established the heavens"). The echo of <em>mispār</em> (number) from v4 is the key: YHWH counts the stars\' number (<em>mispār</em>), yet his own understanding is without number (<em>ʾên mispār</em>). The counter-who-cannot-be-counted.</p>',
    "6": '<p><strong>mĕʿôdēd ʿănāwîm yhwh mašpîl rĕšāʿîm ʿădê-āreṣ</strong> — "the LORD lifts up the humble; he brings the wicked down to the ground." <em>ʿōdēd</em> (lifts up, sustains — Piel participle from <em>ʿûd</em>, to support, restore, refresh; rare form) — the sustained support of those who are bent down. <em>ʿănāwîm</em> (the humble/afflicted/poor — from <em>ʿānāh</em>, to be bowed down, afflicted; the class of those who are socially powerless and have only YHWH as their resource — same word as Ps 37:11 "the meek will inherit the earth" and Num 12:3 "Moses was very meek"). <em>mašpîl rĕšāʿîm ʿădê-āreṣ</em> (casts the wicked to the earth/ground, Hiphil of <em>šāpal</em>) — the reversal pattern that runs through Hannah\'s prayer (1 Sam 2:7–8), the Magnificat (Luke 1:52), and the beatitudes.</p>',
    "7": '<p><strong>ʿănû layhwh bĕtôdāh zammĕrû lēʾlōhênû bĕkinnôr</strong> — "sing to the LORD with thanksgiving; make music to our God with the lyre." The shift from description (vv 1–6) to imperative command marks a new movement. <em>ʿānāh</em> (respond, answer in song — Qal imperative; the verb used in the antiphonal singing of Exod 15:21 and 1 Sam 18:7) with <em>tôdāh</em> (thanksgiving, the thank-offering — from <em>yādāh</em>, to confess/praise; <em>tôdāh</em> refers both to the spoken thanks and the sacrificial offering that accompanies it, Lev 7:12). <em>zāmar</em> (make music on a stringed instrument — Piel imperative, the root of <em>mizmôr</em> = psalm; consistently used for instrumental music as distinct from vocal praise). <em>kinnôr</em> (lyre/harp — the instrument of David and the Levitical choir).</p>',
    "8": '<p><strong>hamĕkassēh šāmayim bĕʿābîm hammēkîn lāʾāreṣ māṭār hammāṣmîaḥ hārîm ḥāṣîr</strong> — "he covers the sky with clouds, prepares rain for the earth, makes grass grow on the hills." Three Hiphil participles in sequence, each presenting YHWH as the ongoing agent of natural provision: <em>kāsāh</em> (covers, Piel), <em>kûn</em> (prepares/establishes, Hiphil), <em>ṣāmaḥ</em> (causes to grow, Hiphil). The sequence — clouds → rain → grass — traces the supply chain of agricultural life. The theological force is anti-Baʿal polemic: the Canaanite storm-god Baʿal was credited with sending rain; the psalm insists it is YHWH who prepares (actively, purposefully) rain for the earth. <em>ḥāṣîr</em> (grass/hay/green vegetation) on the mountains points to vv 8–9\'s chain: vegetation feeds animals; YHWH is the fountainhead of the entire food system.</p>',
    "9": '<p><strong>nôtēn libhēmāh laḥmāh libĕnê ʿōrēb ʾăšer yiqrāʾû</strong> — "he gives to the beast its food, and to the young ravens when they call." <em>bĕhēmāh</em> (beast — large quadruped, domestic or wild; the general animal class) — YHWH provides food for animals in general before the ravens are specified. <em>bĕnê ʿōrēb</em> (sons of the raven, young ravens) — ravens were classified as unclean birds under Levitical law (Lev 11:15; Deut 14:14) and yet YHWH feeds their young. <em>ʾăšer yiqrāʾû</em> (who call/cry out) — the ravens\' cries are presented as a form of petition that YHWH hears and answers; Job 38:41 uses the same image ("who provides for the raven its prey, when its young ones cry to God?"). Jesus echoes this in Luke 12:24 ("consider the ravens; they do not sow or reap... and yet God feeds them").</p>',
    "10": '<p><strong>lōʾ bigĕbûrat hassûs yĕḥpāṣ lōʾ bĕšôqê hāʾîš yirṣeh</strong> — "he does not delight in the strength of the horse, nor take pleasure in the legs of a man." The verse is structured as a double negative: <em>lōʾ... yĕḥpāṣ</em> (does not delight in) / <em>lōʾ... yirṣeh</em> (does not take pleasure in). <em>gĕbûrat hassûs</em> (strength/might of the horse) — in the ANE, the horse was the decisive weapon of war; Egyptian and Assyrian armies were feared for their cavalry. <em>šôqê hāʾîš</em> (legs/thighs of a man) — the legs of an infantryman, his physical power. Both are military metaphors: YHWH is not impressed by conventional military strength (Ps 20:7; Isa 31:1; Deut 17:16 — the king must not multiply horses). Human military power is irrelevant to divine favor.</p>',
    "11": '<p><strong>rôṣeh yhwh ʾet-yĕrēʾāyw ʾet-hamĕyaḥălîm lĕḥasdô</strong> — "the LORD takes pleasure in those who fear him, in those who hope in his steadfast love." The contrast with v10 is sharp: YHWH\'s <em>rāṣāh</em> (pleasure, favorable regard) is not given to military power but to a spiritual disposition. <em>yĕrēʾāyw</em> (those who fear him — Qal participle plural of <em>yārēʾ</em>; the fundamental posture of covenantal reverence that combines awe, obedience, and trust). <em>hamĕyaḥălîm lĕḥasdô</em> (those who hope/wait in his steadfast love) — <em>yāḥal</em> (to wait with expectant hope, Piel participle) + <em>ḥesed</em> (covenant loyalty, steadfast love — the central Hebrew theological term for YHWH\'s faithful, committed love within the covenant relationship). The combination is the Psalter\'s definition of godly life: reverential fear of YHWH coupled with hopeful waiting on his covenant faithfulness.</p>',
    "12": '<p><strong>šabbĕḥî yĕrûšālayim ʾet-yhwh hallĕlî ʾĕlōhayik ṣiyyôn</strong> — "praise the LORD, O Jerusalem! Praise your God, O Zion!" The second half of the psalm (vv 12–20) begins with a direct address to Jerusalem/Zion — a shift from the general praise of vv 1–11. <em>šābaḥ</em> (praise, commend, laud — Piel imperative; slightly distinct from <em>hālal</em>; <em>šābaḥ</em> tends toward public proclamation and commendation of another\'s excellence). The personification of Jerusalem as a praising subject is characteristic of the Songs of Zion (Ps 48; 87; Isa 40:9; 52:1). The LXX counts this as the beginning of a new psalm (LXX Psalm 147), suggesting early Jewish recognition of its distinct character.</p>',
    "13": '<p><strong>kî ḥizzaq bĕrîḥê šĕʿārayik bērēk bānayik bĕqirbēk</strong> — "for he has reinforced the bars of your gates and blessed your children within you." <em>ḥizzaq</em> (reinforced/strengthened — Piel perfect of <em>ḥāzaq</em>) the <em>bĕrîḥîm</em> (crossbars/locking bars) of the <em>šĕʿārîm</em> (gates) — the practical image of Nehemiah\'s rebuilding: the gate-bars that lock the city against siege or attack (Neh 3:3, 6, 13; 7:3). The bars of the gates represent the entire defensive infrastructure of restored Jerusalem. The verse pairs external security (bars of gates) with internal blessing (children within) — the city restored to both protection and fertility.</p>',
    "14": '<p><strong>haśśām-gĕbûlēk šālôm ḥēleb ḥiṭṭîm yaśbîʿēk</strong> — "he makes peace your border, and satisfies you with the finest wheat." <em>šālôm</em> as the content of borders — the territory under YHWH\'s covenant protection is not defined merely by geography but by wholeness and well-being. <em>ḥēleb ḥiṭṭîm</em> (finest/fat of wheat) — <em>ḥēleb</em> (fat, the richest portion; same word as the fat reserved for sacrifice in Lev 3:16) applied to wheat = the choicest grain. The fat of wheat as temple provision (Deut 32:14 refers to Israel being fed "the finest of wheat"; Ps 81:16) — the restored community receives sacrificial-quality provision for ordinary sustenance.</p>',
    "15": '<p><strong>haššōlēaḥ ʾimrātô āreṣ ʿad-mĕhērāh yārûṣ dĕbārô</strong> — "he sends his command/word to the earth; his word runs swiftly." <em>ʾimrāh</em> (word/command — from <em>ʾāmar</em>, to say; the specific form that emphasizes authoritative speech) + <em>dābār</em> (word, matter, thing — the comprehensive divine utterance) appear together to emphasize the complete authority of YHWH\'s speech. <em>yārûṣ</em> (runs, Qal imperfect of <em>rûṣ</em>) — the personification of the divine word as a swift messenger racing across the earth. Vv 15–18 then describe the divine word\'s work in nature: it commands snow, frost, hail, cold, and then the thaw. This sequence creates the theological context for v19: the same word that commands weather is the word that commands Israel — Torah and cosmos share one divine speech-act.</p>',
    "16": '<p><strong>hannōtēn šeleg kaṣṣāmer kĕpôr kāʾēper yĕpazzēr</strong> — "he gives snow like wool; he scatters frost like ashes." Two similes: <em>šeleg</em> (snow) compared to <em>ṣemer</em> (wool) — the white, fluffy covering of both; and <em>kĕpôr</em> (hoarfrost, frost crystals) compared to <em>ʾēper</em> (ash/ashes) — the grayish, powdery scatter of both. <em>yĕpazzēr</em> (scatters, Piel imperfect of <em>pāzar</em> — to scatter, spread abroad; the Piel suggests thoroughness of the scattering). The poetic genius is in the domestic images: wool (from the flock) and ash (from the hearth) make cosmic phenomena familiar; YHWH\'s winter provision is as natural as household goods.</p>',
    "17": '<p><strong>mašlîk qārāḥô kĕpittîm lipnê qārātô mî yaʿămōd</strong> — "he hurls down his ice like morsels/crumbs; who can stand before his cold?" <em>qeraḥ</em> (ice, hailstones — solid frozen water; can refer to crystal-clear ice from its appearance) + <em>pittîm</em> (morsels, pieces, crumbs of bread — from <em>pat</em>, a morsel) — hailstones scattered like bread crumbs; the image is both vivid (size and quantity) and carries a trace of divine playfulness. <em>mî yaʿămōd</em> (who can stand/withstand?) — a rhetorical question expecting the answer "no one"; the divine cold is an overwhelming force. The question echoes Nah 1:6 ("who can stand before his indignation?") and Mal 3:2 ("who can endure the day of his coming?") — the divine power in nature foreshadows eschatological power.</p>',
    "18": '<p><strong>yišlaḥ dĕbārô wĕyamsēm yašsēb rûḥô yizzĕlû-māyim</strong> — "he sends his word and melts them; he makes his wind blow and the waters flow." The structural echo is precise: v15 sends (<em>šālaḥ</em>) his word to earth; here v18 sends (<em>šālaḥ</em>) his word to melt the ice. The same divine speech-act that produced the cold (vv 16–17) now dissolves it. <em>wĕyamsēm</em> (melts them, Hiphil — causative of <em>māsas</em>, to melt, dissolve; the subject is the divine word melting the snow and frost). <em>yašsēb rûḥô</em> (he makes his wind blow — causes to blow, Hiphil of <em>nāšab</em>) — the warm wind (the sirocco/east wind that dries and thaws in the Levant); the same <em>rûaḥ</em> (wind/spirit) that swept over the waters at creation (Gen 1:2). <em>yizzĕlû-māyim</em> (the waters flow — Qal imperfect, the resulting thaw and runoff).</p>',
    "19": '<p><strong>maggid dĕbārô lĕyaʿăqōb ḥuqqāyw ûmišpāṭāyw lĕyiśrāʾēl</strong> — "he declares his word to Jacob, his statutes and ordinances to Israel." The transition from cosmic <em>dābār</em> (vv 15–18) to covenantal <em>dābār</em> is the theological climax. <em>maggid</em> (declares/makes known — Hiphil participle of <em>nāgad</em>, to tell, report, declare) emphasizes the communicative act: YHWH does not merely possess his word but speaks it to Jacob. <em>ḥuqqāyw</em> (his statutes — from <em>ḥāqaq</em>, to engrave, decree; specific covenant terms) + <em>mišpāṭāyw</em> (his judgments/ordinances — the case-law of covenant governance). <em>yiśrāʾēl</em> (Israel) + <em>yaʿăqōb</em> (Jacob) — the covenant double-name; the two names together indicate the whole people under both their ancestral name (Jacob) and their covenant-struggle name (Israel).</p>',
    "20": '<p><strong>lōʾ-ʿāśāh kēn lĕkol-gôy ûmišpāṭîm bal-yĕdāʿûm hallĕlû-yāh</strong> — "he has not done this for any other nation; they do not know his ordinances. Praise the LORD!" The exclusivity of the covenant-gift is stated plainly and without apology: <em>lōʾ-ʿāśāh kēn</em> (he has not done so) <em>lĕkol-gôy</em> (for any nation — the word <em>gôy</em>, nation, is used for non-Israelite peoples; here it is all-inclusive: no nation has received what Israel received). <em>ûmišpāṭîm bal-yĕdāʿûm</em> (they do not know his judgments — <em>bal</em> is the emphatic negation; the nations have simply not been given the Torah). This is a statement of historical election, not an assertion of the nations\' moral worthlessness; Paul takes up the same theme in Rom 9:4–5 and 3:1–2 ("what advantage has the Jew? Much in every way; first, they were entrusted with the oracles of God"). <em>hallĕlû-yāh</em> — the doxological close.</p>',
  },
  "148": {
    "1": '<p><strong>hallĕlû-yāh hallĕlû ʾet-yhwh min-haššāmayim hallĕlûhû bammĕrômîm</strong> — "Praise the LORD! Praise the LORD from the heavens; praise him in the heights above!" The opening triple use of <em>hallĕlû</em> (praise — Piel imperative plural of <em>hālal</em>; the root of Hallel and Hallelujah) immediately establishes the cosmic register. <em>min-haššāmayim</em> (from the heavens) — the praise is summoned from above; heaven is not merely where God dwells but from where praise is called down. <em>bammĕrômîm</em> (in the heights above — from <em>rûm</em>, to be high; the superlative elevation). The structure of the psalm (vv 1–6 heaven; vv 7–12 earth; vv 13–14 climax) creates a praise that moves from the highest point of creation downward to encompass everything.</p>',
    "2": '<p><strong>hallĕlûhû kol-mallāʾkāyw hallĕlûhû kol-ṣĕbāʾōtāyw</strong> — "Praise him, all his angels! Praise him, all his hosts/heavenly armies!" <em>mallāʾkāyw</em> (his angels/messengers — from <em>mālāʾk</em>, messenger, envoy; the divine attendants who serve in the heavenly court). <em>ṣĕbāʾōtāyw</em> (his hosts/armies — <em>ṣābāʾ</em>, host or army; the term for the divine warrior\'s forces, as in the divine title YHWH ṣĕbāʾôt, "LORD of hosts"). The angelic host is called to praise before the natural order; the heavenly court leads the cosmic liturgy. Ps 103:20–21 uses the same pairing: "bless the LORD, all his angels... all his hosts, his ministers."</p>',
    "3": '<p><strong>hallĕlûhû šemeš wĕyārēaḥ hallĕlûhû kol-kôkĕbê ʾôr</strong> — "Praise him, sun and moon; praise him, all you shining stars!" The luminaries of Genesis 1:14–18 — <em>šemeš</em> (sun, the great light), <em>yārēaḥ</em> (moon, the lesser light) — are called to praise. <em>kôkĕbê ʾôr</em> (stars of light/shining stars) — all the lesser luminaries. The sun and moon were among the most prominent objects of ANE worship (Shamash the sun-god; Sin the moon-god in Mesopotamia; Shemesh in Canaan). Ps 148\'s call to these astral bodies to praise YHWH is an implicit polemic: the objects other nations worship are themselves worshippers, summoned to praise the one who made them.</p>',
    "4": '<p><strong>hallĕlûhû šĕmê haššāmayim wĕhammayim ʾăšer mēʿal haššāmayim</strong> — "Praise him, you highest heavens, and you waters above the heavens!" <em>šĕmê haššāmayim</em> (heavens of the heavens, the superlative — literally "skies of the skies") — the divine abode beyond the created heavens (Deut 10:14; 1 Kgs 8:27; Ps 115:16). <em>hammayim ʾăšer mēʿal haššāmayim</em> (the waters above the heavens) — the cosmological upper waters of Gen 1:7 that are above the rāqîaʿ (firmament). The psalm takes the full ANE cosmological model and calls every tier of it to praise. The waters that were separated at creation (Gen 1:6–7) now join in the praise-order rather than threatening the ordered world.</p>',
    "5": '<p><strong>yĕhallĕlû ʾet-šēm yhwh kî hûʾ ṣiwwāh wĕnibrāʾû</strong> — "let them praise the name of the LORD, for he commanded and they were created." <em>ṣiwwāh</em> (commanded — Piel perfect of <em>ṣāwāh</em>; the decisive divine command) + <em>nibrāʾû</em> (and they were created — Niphal perfect of <em>bārāʾ</em>, the distinctive creation verb used in Gen 1:1). The creation formula: the word and the act are simultaneous. This is the deepest possible basis for praise: the praising creatures exist because of the divine command. The <em>kî</em> (for/because) clause makes this the warrant for all cosmic praise — every creature praises because it was commanded into existence.</p>',
    "6": '<p><strong>wayyaʿămîdēm lāʿad lĕʿôlām ḥōq-nātan wĕlōʾ yaʿăbôr</strong> — "he has established them forever and ever; he has issued a decree that cannot be transgressed." <em>wayyaʿămîdēm</em> (he established/stationed them — Hiphil wayyiqtol of <em>ʿāmad</em>, to stand; the causative: he made them stand permanently). <em>lāʿad lĕʿôlām</em> (forever and ever — the doubled temporal expression for eternity). <em>ḥōq</em> (decree/statute — the fixed law governing the regular behavior of natural phenomena; the same word used in Jer 5:22 where YHWH gives the sea its boundary-decree). <em>wĕlōʾ yaʿăbôr</em> (and it will not pass away/be transgressed — <em>ʿābar</em>, to pass over, exceed, transgress). The regularity of the seasons, the fixed paths of the stars — all governed by YHWH\'s unchangeable decree.</p>',
    "7": '<p><strong>hallĕlû ʾet-yhwh min-hāʾāreṣ tannînîm wĕkol-tĕhōmôt</strong> — "Praise the LORD from the earth, you sea monsters and all ocean depths!" The shift to the earth-section (vv 7–12) begins with the most dramatic reversal: <em>tannînîm</em> (sea dragons/monsters — plural of <em>tannîn</em>; the term used for the chaos-creatures in Ps 74:13–14 ["You divided the sea by your might; you broke the heads of the sea monsters"] and Job 7:12). In ANE mythology these were the primordial chaos beings YHWH conquered at creation (Leviathan, Tiamat). Here they are called to praise — the chaos-monsters are worshippers, not threats. <em>tĕhōmôt</em> (ocean deeps, from <em>tĕhôm</em> — the deep of Gen 1:2, cognate with Akkadian Tiamat) — the depths called to praise alongside the monsters they harbor.</p>',
    "8": '<p><strong>ʾēš ûbārād šeleg wĕqîṭôr rûaḥ sĕʿārāh ʿōśāh dĕbārô</strong> — "fire and hail, snow and mist, stormy wind fulfilling his word." Four elements of violent weather: <em>ʾēš</em> (fire — lightning), <em>bārād</em> (hail — the same term in the plagues of Exod 9:18–26), <em>šeleg</em> (snow), <em>qîṭôr</em> (mist/vapor/smoke — used of the smoke of incense, Gen 19:28). The unifying phrase is <em>ʿōśāh dĕbārô</em> (fulfilling/doing his word — participle of <em>ʿāśāh</em>): the violent weather phenomena are not chaos but servants executing YHWH\'s commands. The same logic as the divine warrior\'s weapons: natural catastrophe as divine instrument (cf. Ps 147:15–18 where the divine word commands weather).</p>',
    "9": '<p><strong>hehārîm wĕkol-gĕbāʿôt ʿêṣ pĕrî wĕkol-ʾărazîm</strong> — "mountains and all hills, fruit trees and all cedars." The geographical and botanical inventory: <em>hārîm</em> (mountains, the great elevations) + <em>gĕbāʿôt</em> (hills, the lesser heights) — the entire relief of the land. <em>ʿêṣ pĕrî</em> (fruit tree — literally "tree of fruit," the cultivated orchard) + <em>ʾărazîm</em> (cedars — the <em>ʾerez</em>, the great wild tree of Lebanon, symbol of height and majesty, Ps 92:12; 104:16). The cultivated and wild botanical realms both praise.</p>',
    "10": '<p><strong>haḥayyāh wĕkol-bĕhēmāh remeś wĕṣippôr kānāp</strong> — "wild beasts and all livestock, creeping things and flying birds." The standard zoological categories of the Hebrew world: <em>ḥayyāh</em> (wild beast, living thing — the untamed animals of the field) + <em>bĕhēmāh</em> (livestock/domestic animals) + <em>remes</em> (creeping thing — the crawling creatures of the earth, Gen 1:24) + <em>ṣippôr kānāp</em> (bird of wing — a compound intensifying the flight characteristic; every winged flier). The four animal categories match the creation taxonomy of Gen 1:20–25.</p>',
    "11": '<p><strong>malkê-ʾereṣ wĕkol-lĕʾummîm śārîm wĕkol-šōpĕṭê āreṣ</strong> — "kings of the earth and all peoples, princes and all judges of the earth." The political order is called to praise. <em>malkê-ʾereṣ</em> (kings of the earth) — the highest human authority; <em>lĕʾummîm</em> (peoples, nations — plural of <em>lĕʾom</em>, a people-group; distinct from <em>gôy</em> in that <em>lĕʾom</em> emphasizes the communal solidarity). <em>śārîm</em> (princes, officials — the secondary power-holders) + <em>šōpĕṭîm</em> (judges — the judicial authority). Every tier of human governance is subsumed under the praise of YHWH; the same kings who issue decrees are themselves called to declare the greatness of the one who issues cosmic decrees (v6).</p>',
    "12": '<p><strong>bĕḥûrîm wĕgam-bĕtûlôt zĕqēnîm ʿim-nĕʿārîm</strong> — "young men and also young women together, old men with children." The age spectrum of humanity: <em>bĕḥûrîm</em> (young men — the vigorous, marriageable males) + <em>bĕtûlôt</em> (young women/virgins — from <em>bĕtûlāh</em>, a young woman of marriageable age) + <em>zĕqēnîm</em> (old men/elders — the socially senior) + <em>nĕʿārîm</em> (children/young ones — the socially junior). The <em>gam</em> (also, even) before the women marks an inclusiveness: not just men but also women. This age-and-gender inclusiveness completes the human catalog before the climactic verses.</p>',
    "13": '<p><strong>yĕhallĕlû ʾet-šēm yhwh kî-niśgāb šĕmô lĕbaddô hôdô ʿal-ʾereṣ wĕšāmāyim</strong> — "let them praise the name of the LORD, for his name alone is exalted; his splendor is above earth and heaven." <em>niśgāb šĕmô</em> (his name is exalted/set on high — Niphal of <em>śāgab</em>, to be inaccessibly high, beyond reach) — the name that is beyond the reach of any competing name. <em>lĕbaddô</em> (alone, by himself, exclusively — from <em>bādad</em>, to be separate/isolated; the emphasis on YHWH\'s exclusive majesty). <em>hôdô</em> (his splendor/majesty — from <em>hôd</em>, the majestic presence; related to the visible glory) <em>ʿal-ʾereṣ wĕšāmāyim</em> (above earth and heaven) — a merism: the entire created order is encompassed and transcended by YHWH\'s glory.</p>',
    "14": '<p><strong>wayyārem qeren lĕʿammô tĕhillāh lĕkol-ḥăsîdāyw libĕnê yiśrāʾēl ʿam-qĕrōbô hallĕlû-yāh</strong> — "he has raised high the horn of his people, the praise of all his faithful ones, of the children of Israel, the people near to him. Praise the LORD!" <em>wayyārem qeren</em> (he raised/lifted the horn — Hiphil wayyiqtol of <em>rûm</em>, to raise; <em>qeren</em>, horn — the horn as the symbol of strength and honor; to have one\'s horn raised = to be vindicated, exalted, given honor; 1 Sam 2:10; Ps 89:17, 24; 132:17). The horn raised for <em>ʿammô</em> (his people) is the covenant-community\'s vindication, not just an individual\'s. <em>ḥăsîdāyw</em> (his devoted/faithful ones — from <em>ḥesed</em>; those who embody covenant loyalty, the same community as in Ps 149:1, 5, 9). <em>ʿam-qĕrōbô</em> (the people near to him — from <em>qārab</em>, to draw near; the priestly term for approaching YHWH in the sanctuary, here describing Israel\'s covenantal intimacy with YHWH). The closing <em>hallĕlû-yāh</em> seals the cosmic praise with the covenant community\'s own doxological word.</p>',
  },
  "149": {
    "1": '<p><strong>hallĕlû-yāh šîrû layhwh šîr ḥādāš tĕhillātô biqhal ḥăsîdîm</strong> — "Praise the LORD! Sing to the LORD a new song; his praise in the assembly of the faithful." <em>šîr ḥādāš</em> (new song — the phrase appears at Ps 33:3; 40:3; 96:1; 98:1; 144:9; Isa 42:10; Rev 5:9; 14:3; always in response to a new or decisive act of divine salvation). The newness is not aesthetic novelty but theological freshness: each new divine act of redemption requires a new praise-response. <em>biqhal ḥăsîdîm</em> (in the assembly of the faithful/devoted — from <em>qāhal</em>, the assembled community of Israel, and <em>ḥăsîdîm</em>, those characterized by <em>ḥesed</em>, covenant loyalty). The <em>ḥăsîdîm</em> are this psalm\'s central subject — they appear in vv 1, 5, and 9, forming an inclusio.</p>',
    "2": '<p><strong>yiśmaḥ yiśrāʾēl bĕʿōśāyw bĕnê-ṣiyyôn yāgîlû bĕmalkām</strong> — "let Israel rejoice in their Maker; let the people of Zion be joyful in their King." <em>ʿōśāyw</em> (their Maker — Qal active participle of <em>ʿāśāh</em>, to make/do; plural of majesty construction — not "their makers" but the one Maker described by a plural of excellence). <em>yiśmaḥ</em> (rejoice — Qal jussive of <em>śāmaḥ</em>) + <em>yāgîlû</em> (be joyful — Qal jussive of <em>gîl</em>, to exult, spin with joy; a more exuberant word than <em>śāmaḥ</em>). <em>malkām</em> (their King) — YHWH as the divine King of Zion; the title connects the rejoicing community to the royal enthronement psalms (Ps 93; 95–99).</p>',
    "3": '<p><strong>yĕhallĕlû šĕmô bĕmaḥôl bĕtōp wĕkinnôr yĕzammĕrû-lô</strong> — "let them praise his name with dancing; let them make music to him with tambourine and lyre." <em>māḥôl</em> (dance — the round dance, celebratory movement; used of Miriam\'s dance in Exod 15:20 and David\'s before the ark in 2 Sam 6:14). <em>tōp</em> (tambourine/hand-drum — the instrument Miriam took up after the Reed Sea, Exod 15:20) + <em>kinnôr</em> (lyre/harp — David\'s instrument). The echo of the Exodus praise-instruments situates Ps 149\'s praise within the tradition of Israel\'s great victory celebrations. The worship is fully embodied: voice (praise), movement (dance), and multiple instruments.</p>',
    "4": '<p><strong>kî-rōṣeh yhwh bĕʿammô yĕpāʾēr ʿănāwîm bîšûʿāh</strong> — "for the LORD takes pleasure in his people; he adorns the humble with salvation." <em>rāṣāh</em> (takes pleasure/delight in — Qal imperfect; the same verb as Ps 147:11 where YHWH takes pleasure in those who fear him and hope in his <em>ḥesed</em>; here the object is simply <em>ʿammô</em>, his people). <em>yĕpāʾēr</em> (adorns/beautifies/glorifies — Piel imperfect of <em>pāʾar</em>, to beautify, adorn, glorify; the Piel of intensive beautification) the <em>ʿănāwîm</em> (humble/poor/afflicted — the same class as Ps 147:6) with <em>yĕšûʿāh</em> (salvation, victory — the root of the name Jesus/<em>Yĕšûaʿ</em>). Salvation as an adornment: the humble are clothed in divine victory, which functions as their honor-garment in a society where honor was everything.</p>',
    "5": '<p><strong>yĕʿallzû ḥăsîdîm bĕkābôd yĕrannĕnû ʿal-miškĕbôtām</strong> — "let the faithful exult in glory; let them sing aloud even on their beds." <em>ʿālaz</em> (exult — Qal imperfect of <em>ʿālaz</em>, to rejoice, be jubilant; a strong emotional word for exuberant joy). <em>bĕkābôd</em> (in glory — either YHWH\'s glory as the ground of their exultation, or the glory that accrues to the <em>ḥăsîdîm</em> through the divine vindication of v4). <em>yĕrannĕnû</em> (sing aloud with joy — Piel imperfect of <em>rānan</em>, to ring out in joy, to shout aloud; the root of <em>rinnāh</em>, the ringing cry of praise) <em>ʿal-miškĕbôtām</em> (on their beds) — even in sleep-settings, the praise continues; possibly the night-vigil of those who meditate on YHWH in the night watches (Ps 63:6; 119:55). The midnight praise is as genuine as the daylight assembly.</p>',
    "6": '<p><strong>rômmôt ʾēl bigĕrônām wĕḥereb pîpiyyôt bĕyādām</strong> — "with the high praises of God in their throats and a double-edged sword in their hands." The psalm\'s most striking image: two paired instruments of the <em>ḥăsîdîm</em>. <em>rômmôt ʾēl</em> (high praises of God — plural of <em>rômāh</em>, high things, exaltations; from <em>rûm</em>, to be high; these are praises that exalt God to his proper height). <em>bigĕrônām</em> (in their throats/gullets — from <em>gārôn</em>, the throat as the channel of vocal sound; Ps 115:7 uses it for throats that do not speak). <em>ḥereb pîpiyyôt</em> (double-edged sword — literally "sword of mouths"; <em>peh</em> = mouth; a sword with two mouths/edges, both cutting). The same image appears in Rev 19:15 (the rider\'s sword from his mouth) and Heb 4:12 (the word of God as a two-edged sword). The <em>ḥăsîdîm</em> are simultaneously worshippers and warriors — their praise and their action both serve YHWH\'s purposes.</p>',
    "7": '<p><strong>laʿăśôt nĕqāmāh baggôyim tôkĕḥôt bĕlĕʾummîm</strong> — "to execute vengeance on the nations and punishment on the peoples." <em>nĕqāmāh</em> (vengeance — from <em>nāqam</em>, to avenge; YHWH\'s vengeance is judicial rather than personal; the divine warrior\'s act of setting right what was wronged). The <em>ḥăsîdîm</em> act as agents of this divine judicial action — not as initiators of personal revenge but as instruments through whom YHWH executes judgment. <em>tôkĕḥôt</em> (punishments/corrections — from <em>yākaḥ</em>, to reprove, correct, decide; the judicial sense of warranted correction, not arbitrary violence). The scope — nations and peoples — suggests an eschatological or historical judgment rather than an individual grievance.</p>',
    "8": '<p><strong>lĕʾsōr malkêhem bĕziqîm wĕnikabbĕdêhem bĕkablê barzel</strong> — "to bind their kings in chains and their nobles in iron fetters." <em>ʾāsar</em> (bind — Qal infinitive construct with <em>lĕ</em>; the binding of captives as the completion of military victory, Josh 10:24; Judg 1:7). <em>ziqîm</em> (chains — restraints for prisoners) + <em>kablê barzel</em> (iron fetters — from <em>kebesel</em>, fetter; the iron chains of serious imprisonment, Ps 107:10, 14). <em>nikabbĕdêhem</em> (their nobles/honored ones — Niphal participle of <em>kābad</em>, to be heavy/honored; those who have social weight and dignity). The binding of kings and nobles in iron chains is the imagery of complete military conquest; the enemies who exalted themselves are brought low.</p>',
    "9": '<p><strong>laʿăśôt bāhem mišpāṭ kātûb hādār hûʾ lĕkol-ḥăsîdāyw hallĕlû-yāh</strong> — "to execute on them the judgment that is written — this is the honor/glory of all his faithful ones. Praise the LORD!" <em>mišpāṭ kātûb</em> (the judgment that is written — the decree already recorded in Scripture; most naturally Deut 28–32, the covenant curses that would come upon the nations that oppose YHWH\'s people, or more broadly the Torah\'s prophetic vision of divine justice). <em>hādār hûʾ lĕkol-ḥăsîdāyw</em> (this is the honor/splendor for all his faithful ones — <em>hādār</em>, the majestic honor/beauty, same word as YHWH\'s <em>hôd wĕhādār</em> in Ps 104:1; 111:3). The privilege of executing YHWH\'s written judgment is itself the <em>hādār</em> of the <em>ḥăsîdîm</em> — their dignity comes from participating in divine justice, not from inherent status. <em>hallĕlû-yāh</em> — the doxological close that mirrors v1\'s opening.</p>',
  },
  "150": {
    "1": '<p><strong>hallĕlû-yāh hallĕlû-ʾēl bĕqodšô hallĕlûhû birqîaʿ ʿuzzô</strong> — "Praise the LORD! Praise God in his sanctuary; praise him in the vault of his power!" The Grand Doxology of the Psalter opens with three instances of <em>hallĕlû</em> in one verse. <em>bĕqodšô</em> (in his sanctuary/holiness — either the earthly temple in Jerusalem or the heavenly sanctuary where YHWH dwells; Ps 11:4 places YHWH "in his holy temple" while also "in heaven"). <em>birqîaʿ ʿuzzô</em> (in the firmament/vault of his power — <em>rāqîaʿ</em> from <em>rāqaʿ</em>, to beat out, spread out; the expanse of Gen 1:6–8 stretched out as the created sky; here it is described as <em>ʿuzzô</em>, his power, making the cosmic vault YHWH\'s display of might). The two locations — sanctuary and firmament — locate praise in both the earthly liturgy and the cosmic order.</p>',
    "2": '<p><strong>hallĕlûhû bigĕbûrōtāyw hallĕlûhû kĕrōb gūdlô</strong> — "praise him for his mighty deeds; praise him according to the fullness of his greatness." <em>bigĕbûrōtāyw</em> (for/in his mighty deeds — from <em>gĕbûrāh</em>, might, heroic act; plural emphasizes the multiplicity of YHWH\'s powerful interventions in history: creation, Exodus, conquest, restoration). <em>kĕrōb gūdlô</em> (according to the fullness/abundance of his greatness — <em>rōb</em> from <em>rābab</em>, to be great in number; the overwhelming vastness of YHWH\'s <em>gōdel</em>, greatness). The praise is to be proportionate to its object: immeasurable greatness warrants immeasurable praise.</p>',
    "3": '<p><strong>hallĕlûhû bĕteqaʿ šôpār hallĕlûhû bĕnebel wĕkinnôr</strong> — "praise him with the blast of the trumpet; praise him with harp and lyre." <em>šôpār</em> (ram\'s horn — the oldest and most significant Israelite wind instrument; used to signal the Sinai theophany, Exod 19:13, 16, 19; to assemble the covenant community, Num 10:10; to announce the Jubilee year, Lev 25:9; and to mark warfare and divine arrival, Josh 6). The <em>šôpār</em> begins the instrumental catalog with the instrument most associated with covenant-assembly and divine presence. <em>nebel</em> (harp/lute — a large-bodied stringed instrument, plucked; associated with the prophets, 1 Sam 10:5) + <em>kinnôr</em> (lyre — David\'s smaller, portable instrument; the instrument of poetry and the Levitical choir).</p>',
    "4": '<p><strong>hallĕlûhû bĕtōp ûmāḥôl hallĕlûhû bĕminnîm wĕʿûgāb</strong> — "praise him with tambourine and dancing; praise him with strings and flute." <em>tōp</em> (tambourine/hand-drum — the membrane percussion instrument) + <em>māḥôl</em> (dance — the praise-dance; uniquely here dance is listed alongside instruments as a mode of praise). <em>minnîm</em> (strings — from <em>mîn</em>, a kind or class; the plural refers to stringed instruments as a class, not a specific instrument). <em>ʿûgāb</em> (flute/pipe — a wind instrument, possibly a flute or Pan-pipe; the word appears in Gen 4:21 as an instrument of Jubal, "the father of all who play the flute"; rare term, suggesting a specific instrument distinct from the <em>šôpār</em>). The verse uniquely includes dance as a praise-medium alongside instruments, incorporating the full-body worship of Ps 149:3.</p>',
    "5": '<p><strong>hallĕlûhû bĕṣilṣĕlê šāmaʿ hallĕlûhû bĕṣilṣĕlê tĕrûʿāh</strong> — "praise him with resounding cymbals; praise him with clashing cymbals." Two types of cymbals receive two verses: <em>ṣilṣĕlê šāmaʿ</em> (cymbals of sound/hearing — cymbals that make their sound heard; the <em>šāmaʿ</em> form may indicate a sustained ring) and <em>ṣilṣĕlê tĕrûʿāh</strong> (cymbals of the shout/alarm — <em>tĕrûʿāh</em> is the great shout used in warfare, at covenant renewal, and at the sound of the ram\'s horn, Num 10:5–6; Ps 89:16; Ezra 3:11–13). <em>ṣilṣal</em> is an onomatopoeic word imitating the sound of clashing metal — the word itself rings out. The climactic position of cymbals in the catalog is fitting: they are the loudest percussion, bringing the instrumental praise to its sonic apex before the verbal conclusion of v6.</p>',
    "6": '<p><strong>kōl hanĕšāmāh tĕhallēl yāh hallĕlû-yāh</strong> — "let everything that has breath praise the LORD! Praise the LORD!" The most expansive possible invitation: <em>kōl hanĕšāmāh</em> (everything that has breath — <em>kōl</em>, all/every; <em>nĕšāmāh</em>, breath, the divine breath of life). <em>nĕšāmāh</em> is the word used in Gen 2:7 for the breath YHWH breathed into Adam: "he breathed into his nostrils the <em>nĕšāmat ḥayyîm</em> (breath of life) and man became a living being." Every creature that carries this original divine gift of breath is included in the final praise. The Psalter that began with "blessed is the man" (Ps 1:1) — a single, righteous individual — ends with <em>kōl hanĕšāmāh</em> — every breathing being without exception. The closing double <em>hallĕlû-yāh</em> seals not just this psalm but the entire Psalter: the final word of the 150-psalm collection is praise.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    print('Psalms 147–150 mkt-original written.')

if __name__ == '__main__':
    main()
